import{_ as i,o as a,c as e,a3 as r}from"./chunks/framework.CS9vaShW.js";const s=JSON.parse('{"title":"量化交易系统架构类博客写作指导","description":"","frontmatter":{},"headers":[],"relativePath":"public/prompt/博客/文章模板/量化交易系统架构.md","filePath":"public/prompt/博客/文章模板/量化交易系统架构.md","lastUpdated":1784048876000}'),t={name:"public/prompt/博客/文章模板/量化交易系统架构.md"};function o(p,l,h,d,n,u){return a(),e("div",null,[...l[0]||(l[0]=[r('<h1 id="量化交易系统架构类博客写作指导" tabindex="-1">量化交易系统架构类博客写作指导 <a class="header-anchor" href="#量化交易系统架构类博客写作指导" aria-label="Permalink to &quot;量化交易系统架构类博客写作指导&quot;">​</a></h1><h2 id="文章定位" tabindex="-1">文章定位 <a class="header-anchor" href="#文章定位" aria-label="Permalink to &quot;文章定位&quot;">​</a></h2><p>量化交易系统架构类博客用于记录高频量化交易系统各个模块的架构设计、模块边界、数据流、性能约束、可靠性策略和工程取舍。</p><p>文章内容必须主要来自当前聊天上下文。模板只规定归纳方式和文章结构，不主动扩展聊天中没有讨论过的系统、模块、技术栈或交易策略。</p><p>文章不是投资建议，也不是交易策略推荐。重点是把系统设计问题整理清楚，让以后回看时能快速理解当时讨论了什么模块、为什么这样设计、还有哪些工程风险需要继续验证。</p><h2 id="适用范围" tabindex="-1">适用范围 <a class="header-anchor" href="#适用范围" aria-label="Permalink to &quot;适用范围&quot;">​</a></h2><p>适合用于记录以下主题：</p><ul><li>行情接入、行情标准化、订单簿维护</li><li>策略引擎、信号计算、因子更新</li><li>风控模块、限频限额、熔断和异常保护</li><li>订单管理系统、执行系统、交易网关</li><li>回测系统、仿真撮合、参数评估</li><li>低延迟通信、内存模型、并发模型</li><li>监控告警、日志追踪、指标采集</li><li>部署拓扑、灾备切换、灰度发布</li><li>数据存储、事件回放、审计留痕</li></ul><p>不适合把文章写成：</p><ul><li>具体买卖建议</li><li>可直接用于实盘的完整交易策略</li><li>未经验证的收益承诺或性能承诺</li><li>与当前聊天无关的百科式技术堆砌</li></ul><h2 id="开头摘要与图片位置要求" tabindex="-1">开头摘要与图片位置要求 <a class="header-anchor" href="#开头摘要与图片位置要求" aria-label="Permalink to &quot;开头摘要与图片位置要求&quot;">​</a></h2><p>文章开头不要直接放图片，必须先写一段简短的文章描述。</p><p>开头描述用于 VitePress 首页文章列表和读者快速判断文章主题，应为纯文本段落，不要包含 Markdown 图片、HTML 图片标签或其他会在概览中暴露的图片标记。</p><p>开头描述应控制在 1 段，简明说明：</p><ul><li>本文讨论的系统或模块</li><li>想解决的核心架构问题</li><li>主要设计方向和约束条件</li></ul><p>描述之后再放汇总图片。</p><p>汇总图片建议使用系统架构图、模块关系图、事件流图、交易链路图或延迟路径图。图片应概括全文，不需要覆盖所有细节，重点呈现：</p><ul><li>模块边界</li><li>数据流向</li><li>控制流向</li><li>关键依赖</li><li>性能或可靠性约束</li></ul><h2 id="推荐文章结构" tabindex="-1">推荐文章结构 <a class="header-anchor" href="#推荐文章结构" aria-label="Permalink to &quot;推荐文章结构&quot;">​</a></h2><h3 id="_1-设计背景" tabindex="-1">1. 设计背景 <a class="header-anchor" href="#_1-设计背景" aria-label="Permalink to &quot;1. 设计背景&quot;">​</a></h3><p>说明这篇文章来自当前聊天中的什么问题或系统设计需求。</p><p>重点回答：为什么需要设计这个模块？它服务于高频量化交易系统中的哪条链路？当前要解决的主要工程问题是什么？</p><h3 id="_2-模块目标" tabindex="-1">2. 模块目标 <a class="header-anchor" href="#_2-模块目标" aria-label="Permalink to &quot;2. 模块目标&quot;">​</a></h3><p>明确该模块在系统中的职责。</p><p>建议说明：</p><ul><li>输入是什么</li><li>输出是什么</li><li>负责什么</li><li>不负责什么</li><li>和上下游模块的关系</li></ul><p>不要把模块目标写得过宽。架构文章应优先明确边界，而不是堆叠功能清单。</p><h3 id="_3-核心约束" tabindex="-1">3. 核心约束 <a class="header-anchor" href="#_3-核心约束" aria-label="Permalink to &quot;3. 核心约束&quot;">​</a></h3><p>整理聊天中明确提到的约束条件。</p><p>可以按以下维度组织：</p><ul><li>延迟约束</li><li>吞吐约束</li><li>一致性要求</li><li>可用性要求</li><li>数据完整性要求</li><li>风控和合规要求</li><li>运维可观测性要求</li><li>资源限制，例如 CPU、内存、网络和磁盘</li></ul><p>如果某项约束没有被讨论，不要主动编造具体数值。无法确认的指标应标注“未确认”。</p><h3 id="_4-架构设计" tabindex="-1">4. 架构设计 <a class="header-anchor" href="#_4-架构设计" aria-label="Permalink to &quot;4. 架构设计&quot;">​</a></h3><p>这是文章重点。需要把系统设计整理成清晰的模块结构。</p><p>建议包含：</p><ul><li>模块组成</li><li>核心数据结构</li><li>事件流或调用链路</li><li>同步与异步边界</li><li>状态管理方式</li><li>错误处理方式</li><li>降级和恢复策略</li></ul><p>如果涉及高频链路，应特别说明哪些路径属于关键低延迟路径，哪些路径可以异步化、批处理或延后处理。</p><h3 id="_5-数据流与交易链路" tabindex="-1">5. 数据流与交易链路 <a class="header-anchor" href="#_5-数据流与交易链路" aria-label="Permalink to &quot;5. 数据流与交易链路&quot;">​</a></h3><p>把行情、信号、风控、下单、回报、持仓和日志之间的关系写清楚。</p><p>可以按事件顺序描述：</p><ol><li>行情进入系统</li><li>行情被解析、标准化和分发</li><li>策略计算信号</li><li>风控检查订单</li><li>订单发送到交易网关</li><li>成交或撤单回报进入系统</li><li>状态、日志和指标更新</li></ol><p>如果当前文章只讨论其中一个模块，可以只描述和该模块相关的局部链路。</p><h3 id="_6-关键设计取舍" tabindex="-1">6. 关键设计取舍 <a class="header-anchor" href="#_6-关键设计取舍" aria-label="Permalink to &quot;6. 关键设计取舍&quot;">​</a></h3><p>记录当时讨论中的工程取舍。</p><p>可以围绕以下问题展开：</p><ul><li>低延迟与可维护性如何平衡</li><li>同步调用和异步事件如何划分</li><li>内存态和持久化状态如何划分</li><li>单进程、多进程或分布式如何选择</li><li>简化实现与未来扩展如何取舍</li><li>风控安全与下单速度如何平衡</li></ul><p>不要只写结论，要说明为什么选择该方案，以及它牺牲了什么。</p><h3 id="_7-风险点与验证计划" tabindex="-1">7. 风险点与验证计划 <a class="header-anchor" href="#_7-风险点与验证计划" aria-label="Permalink to &quot;7. 风险点与验证计划&quot;">​</a></h3><p>列出该设计在工程上仍需验证的地方。</p><p>建议包括：</p><ul><li>延迟抖动风险</li><li>丢包、乱序、重复事件风险</li><li>状态不一致风险</li><li>单点故障风险</li><li>交易网关异常风险</li><li>回测与实盘行为偏差</li><li>日志过多影响性能</li><li>监控不足导致问题不可定位</li></ul><p>验证计划应尽量具体，例如压测、回放测试、故障注入、仿真撮合、灰度运行、指标对比等。</p><h3 id="_8-后续迭代" tabindex="-1">8. 后续迭代 <a class="header-anchor" href="#_8-后续迭代" aria-label="Permalink to &quot;8. 后续迭代&quot;">​</a></h3><p>记录下一步可以继续设计或实现的内容。</p><p>可以包括：</p><ul><li>尚未设计的模块</li><li>需要补充的接口定义</li><li>需要确认的性能指标</li><li>需要补充的监控指标</li><li>需要拆分的工程任务</li></ul><h2 id="mermaid-图建议" tabindex="-1">Mermaid 图建议 <a class="header-anchor" href="#mermaid-图建议" aria-label="Permalink to &quot;Mermaid 图建议&quot;">​</a></h2><p>如果文章需要图示，优先使用 Mermaid 表达架构关系，便于在 Markdown 中维护。</p><p>推荐图类型：</p><ul><li><code>flowchart</code>：模块关系、交易链路、事件流</li><li><code>sequenceDiagram</code>：下单链路、风控链路、回报链路</li><li><code>stateDiagram-v2</code>：订单状态机、连接状态机、故障恢复状态</li><li><code>classDiagram</code>：核心数据结构或接口关系</li></ul><p>图示应简洁，不要把所有细节放在一张图里。复杂系统可以拆成多张局部图。</p><h2 id="写作原则" tabindex="-1">写作原则 <a class="header-anchor" href="#写作原则" aria-label="Permalink to &quot;写作原则&quot;">​</a></h2><ul><li>先确定模块边界，再描述内部设计</li><li>先写纯文本描述，再放汇总图，避免 VitePress 首页文章列表显示图片标签</li><li>不逐字复刻聊天记录，要提炼、归纳、重组</li><li>不主动补写聊天中没有讨论过的大段内容</li><li>不编造具体延迟、吞吐、收益或稳定性指标</li><li>不写成交易策略说明书</li><li>不给出直接交易建议</li><li>对未确认的架构假设、性能指标和依赖条件必须明确标注“未确认”</li><li>优先保留模块职责、接口边界、数据流、关键取舍和验证计划</li></ul><h2 id="风险提示" tabindex="-1">风险提示 <a class="header-anchor" href="#风险提示" aria-label="Permalink to &quot;风险提示&quot;">​</a></h2><p>文章结尾保留简短提示：</p><blockquote><p>本文仅为个人学习笔记和系统架构设计整理，不构成任何投资建议或交易建议。高频量化交易系统涉及市场风险、技术风险、合规风险和运维风险，任何实盘部署都应经过充分测试、独立验证和风险评估。</p></blockquote>',66)])])}const _=i(t,[["render",o]]);export{s as __pageData,_ as default};
